	@Inject
	public Model2BlocklyGrammarAccess(GrammarProvider grammarProvider,
			TerminalsGrammarAccess gaTerminals) {
		this.grammar = internalFindGrammar(grammarProvider);
		this.gaTerminals = gaTerminals;
		this.pDomainModel = new DomainModelElements();
		this.pCategoryDef = new CategoryDefElements();
		this.pClassDef = new ClassDefElements();
		this.pFeature = new FeatureElements();
		this.pAttribute = new AttributeElements();
		this.pContainment = new ContainmentElements();
		this.pReference = new ReferenceElements();
		this.pValueInput = new ValueInputElements();
		this.pCardinality = new CardinalityElements();
		this.pUiOptions = new UiOptionsElements();
		this.eUiWidget = new UiWidgetElements();
		this.eUiVariant = new UiVariantElements();
		this.pAttributeType = new AttributeTypeElements();
		this.pSimpleType = new SimpleTypeElements();
		this.eSimpleTypeName = new SimpleTypeNameElements();
		this.pEnumType = new EnumTypeElements();
		this.pEnumLiteral = new EnumLiteralElements();
		this.pConstraintDef = new ConstraintDefElements();
		this.pValidationDef = new ValidationDefElements();
		this.eValidationKind = new ValidationKindElements();
		this.pWorkspaceConfig = new WorkspaceConfigElements();
		this.pWorkspaceOption = new WorkspaceOptionElements();
		this.pStringOption = new StringOptionElements();
		this.pIntOption = new IntOptionElements();
		this.pBoolOption = new BoolOptionElements();
		this.pObjectOption = new ObjectOptionElements();
		this.eBoolVal = new BoolValElements();
	}
	
	protected Grammar internalFindGrammar(GrammarProvider grammarProvider) {
		Grammar grammar = grammarProvider.getGrammar(this);
		while (grammar != null) {
			if ("io.github.plortinus.model2blockly.Model2Blockly".equals(grammar.getName())) {
				return grammar;
			}
			List<Grammar> grammars = grammar.getUsedGrammars();
			if (!grammars.isEmpty()) {
				grammar = grammars.iterator().next();
			} else {
				return null;
			}
		}
		return grammar;
	}
	
	@Override
	public Grammar getGrammar() {
		return grammar;
	}
	
	
	public TerminalsGrammarAccess getTerminalsGrammarAccess() {
		return gaTerminals;
	}

	
