	//  'domain' name=ID
	//  ('codeLanguage' codeLanguage=STRING)?
	//  ('codeFileExtension' codeFileExtension=STRING)?
	//  ('runtimeKind' runtimeKind=STRING)?
	//  (workspace=WorkspaceConfig)?
