	//  ('colour' colour=INT)?
	//  ('label' label=STRING)?
	//  ('message0' message0=STRING)?
	//  ('tooltip' tooltip=STRING)?
	//  ('helpUrl' helpUrl=STRING)?
	//  ('inputsInline' inputsInline=BoolVal)?
	//  (inline?='inline')?
	//  ('code' codeTemplate=STRING)?
	//  '{'
